class Solution {
    public int[] earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        int earliest = getEarliest(n, firstPlayer, secondPlayer);
        int latest = getLatest(n, firstPlayer, secondPlayer);
        return new int[] {earliest, latest};
    }

    private int getEarliest(int n, int firstPlayer, int secondPlayer) {
        int round = 0;
        while (firstPlayer != secondPlayer) {
            firstPlayer = getPosition(firstPlayer, n);
            secondPlayer = getPosition(secondPlayer, n);
            n = (n + 1) / 2;
            round++;
        }
        return round + 1;
    }

    private int getLatest(int n, int firstPlayer, int secondPlayer) {
        int round = 0;
        while (n > 1) {
            if (firstPlayer == 1 && secondPlayer == n || 
                firstPlayer == n && secondPlayer == 1) {
                return round + 1;
            }
            if (firstPlayer <= (n + 1) / 2 && secondPlayer > (n + 1) / 2 ||
                firstPlayer > (n + 1) / 2 && secondPlayer <= (n + 1) / 2) {
                n = (n + 1) / 2;
                round++;
            } else {
                firstPlayer = getPosition(firstPlayer, n);
                secondPlayer = getPosition(secondPlayer, n);
                n = (n + 1) / 2;
                round++;
            }
        }
        return round;
    }

    private int getPosition(int player, int n) {
        if (player <= n / 2) {
            return player * 2;
        } else {
            return (player - n / 2) * 2 - 1;
        }
    }
}
